using System;using System.Collections;using EMILtools.Core;using EMILtools.Extensions;using EMILtools.Systems;using EMILtools.Timers;using Sirenix.OdinInspector;using UnityEngine;using static EMILtools.Timers.CurveValue;using static EMILtools.Core.RectEX<PlayerConfig.MouseZones>;public class PlayerFunctionality : Functionalities<    PlayerController,    IPlayerContextView>{    PlayerConfig cfg => facade.Config; PlayerBlackboard bb => facade.API_Blackboard<PlayerBlackboard>(); PlayerContextData mutateCtx => facade.API_Context<PlayerContextData>();    protected override IState AddModulesHere(PlayerController f)    {        // AddModule(new ExampleModule());        AddModule(new InvunrabilityVisualizaton(facade.Actions.IvunrabilityVisualization, f));        AddModule(new FinishInput(facade.Input.FinishInput, f));        AddModule(new Finisher(facade.Actions.Finisher, f));        AddModule(new HookAttack(facade.Actions.HookAttack, f));        AddModule(new Hook(facade.Input.Hook, f));        AddModule(new SharedFMs.ClampLateralMovement<PlayerController>(f));        AddModule(new SharedFMs.InjectCtxIntoBoundsChecker<PlayerController>(f));        AddModule(new SharedFMs.TakeDmg<PlayerController>(facade.Actions.TakeDamage, f,            new PersistentAction(() => facade.Actions.IvunrabilityVisualization.Publish(facade.API_Context<PlayerContextData>()))));        AddModule(new Jump(f.Input.Jump, f));        AddModule(new Friction(f));        AddModule(new InAir(f));        AddModule(new Look(f.Input.Look, f));        AddModule(new CardinalAttackDirection(f.Input.Look, f));        AddModule(new Attack(f.Input.Attack, f));        var initialState = AddModule(new Move(f.Input.Move, f));        return initialState;    }    protected override void SetupTransitionsForFSM(StateMachine<IPlayerContextView> fsm, IPlayerContextView ctx)    {        // Jump Transitions        fsm.AddAnyTransition<Jump>(new FuncCtxPredicate<IPlayerContextView>(ctx => ctx.isJumping), "Jumping");        fsm.AddTransition<Jump, InAir>(new FuncCtxPredicate<IPlayerContextView>(ctx => !ctx.IsGrounded), "Not Grounded", new Resolves(true,                afterExe: new IResolvable[] { new Wait(0.1f, true), }));        fsm.AddTransition<InAir, Move>(new FuncCtxPredicate<IPlayerContextView>(ctx => ctx.IsGrounded), "Grounded");                        // Attack Transitions        fsm.AddAnyTransition<Attack>(new FuncCtxPredicate<IPlayerContextView>(ctx => ctx.isAttacking), "Attacking");        fsm.AddTransition<Attack, Move>(new FuncCtxPredicate<IPlayerContextView>(ctx => !ctx.isAttacking), "Finished Attacking");                // Hook Transitions        fsm.AddAnyTransition<Hook>(new FuncCtxPredicate<IPlayerContextView>(ctx => ctx.isHooking), "Hooking");        fsm.AddTransition<Hook, Move>(new FuncCtxPredicate<IPlayerContextView>(ctx => !ctx.isHooking), "Finished Hooking");    }        class FinishInput : BoundSetFunctionality<PlayerController, IPlayerContextView, FinishInput.Setter>,        ON_SET    {        PlayerConfig cfg => facade.Config; PlayerBlackboard bb => facade.API_Blackboard<PlayerBlackboard>(); PlayerContextData mutateCtx => facade.API_Context<PlayerContextData>();        public class Setter : DataSetter<bool> { [ShowInInspector] public bool PressedFinish => Get; }        public FinishInput(IPublisher publisher, PlayerController facade) : base(publisher, facade) { }        IDamageable.DamageInfo finisherDmgInfo = new()        {            dmg = 1,            location = IDamageable.DamageLocation.Body,            type = IDamageable.DamageType.Regular        };                public void MutateUsingNewSetValues()        {            if (!SetContext.PressedFinish) return;            if (!mutateCtx.isHookLatchedOntoTarget) return;            if (!mutateCtx.isFinishing) return;            if (!mutateCtx.targetIsFinishInputAvaliable.val)            {                Debug.Log("Finisher FAIL");                Reset();                return;            }            mutateCtx.currentFinishingTarget.TakeDamage(finisherDmgInfo);            Reset();            void Reset()            {                bb.hook.ResetHook();                mutateCtx.isFinishing = false;                mutateCtx.targetIsFinishInputAvaliable = null;            }        }    }            class InvunrabilityVisualizaton : BoundFunctionality<PlayerController, IPlayerContextView>    {        PlayerConfig cfg => facade.Config; PlayerBlackboard bb => facade.API_Blackboard<PlayerBlackboard>(); PlayerContextData mutateCtx => facade.API_Context<PlayerContextData>();        public InvunrabilityVisualizaton(Publisher<IPlayerContextView> publisher, PlayerController facade) : base(publisher, facade) { }                public override void Execute(IPlayerContextView ctx)        {            bb.damageFlasher.Flash(DamageFlasher.FlashType.Invunerable);        }    }        class Finisher : BoundSetFunctionality<PlayerController, IPlayerContextView, Finisher.Setter>,        ON_SET    {        PlayerConfig cfg => facade.Config; PlayerBlackboard bb => facade.API_Blackboard<PlayerBlackboard>(); PlayerContextData mutateCtx => facade.API_Context<PlayerContextData>();        [Serializable]        public class Setter : DataSetter<global::Hook.FinisherContext>        {            [ShowInInspector] public bool FinisherActive { get => Get.finisherActive; set => ExplicitSet(new global::Hook.FinisherContext(value, Get.finisherTimer, Get.HookedBreakout, Get.finisherInputAvaliable, Get.damageable));}            [ShowInInspector] public CountdownTimer FinisherTime => Get.finisherTimer;            [ShowInInspector] public PersistentAction HookedBreakout { get => Get.HookedBreakout; set => ExplicitSet(new global::Hook.FinisherContext(FinisherActive, FinisherTime, value, Get.finisherInputAvaliable, Get.damageable)); }            [ShowInInspector] public Ref<bool> IsFinisherInputAvaliable => Get.finisherInputAvaliable;            [ShowInInspector] public IDamageable Damageable => Get.damageable;        }                Action myCachedHookedBreakoutDelegate;                public Finisher(IPublisher publisher, PlayerController facade) : base(publisher, facade) { }        protected override void Awake() => myCachedHookedBreakoutDelegate = HookedBreakout;        public void MutateUsingNewSetValues()        {            if (!SetContext.FinisherActive) return;            if (mutateCtx.isFinishing) return;            SetContext.HookedBreakout.Clear();            SetContext.HookedBreakout.Add(myCachedHookedBreakoutDelegate);            mutateCtx.isFinishing = true;            mutateCtx.targetIsFinishInputAvaliable = SetContext.IsFinisherInputAvaliable;            mutateCtx.currentFinishingTarget = SetContext.Damageable;            SetContext.FinisherTime.StartAndReset();            Debug.Log("Finisher Activated");        }        public void HookedBreakout()        {            Debug.Log("Finisher: Player knows entity broke out of the hook!");            SetContext.FinisherActive = false;            mutateCtx.isFinishing = false;            mutateCtx.targetIsFinishInputAvaliable = null;            bb.hook.ResetHook();            mutateCtx.isHooking = false;        }    }    class HookAttack : BoundFunctionality<PlayerController, IPlayerContextView>    {        PlayerConfig cfg => facade.Config; PlayerBlackboard bb => facade.API_Blackboard<PlayerBlackboard>(); PlayerContextData mutateCtx => facade.API_Context<PlayerContextData>();        public HookAttack(Publisher<IPlayerContextView> publisher, PlayerController facade) : base(publisher, facade) { }        protected override void Awake()        {            bb.hook.SetupHookAttackFinishedSignal(() =>            {                mutateCtx.isHooking = false;                mutateCtx.isHookLatchedOntoTarget = false;                mutateCtx.targetStunPublisher = null;            });        }        public override PipelineBuilder<IPlayerContextView> InjectSteps(PipelineBuilder<IPlayerContextView> builder)         => builder.Add_ShortCircuit(new FuncCtxPredicate<IPlayerContextView>(ctx => ctx.isFinishing));        public override void Execute(IPlayerContextView ctx)        {            Debug.Log("Stun attempt: Hook Attack!");            bb.hook.HookAttack();            if (ctx.isHookLatchedOntoTarget)            {                ctx.targetStunPublisher.Publish(true);                Debug.Log("Stun attempt successful!");            }        }    }        class Hook : BoundSetFunctionality<PlayerController, IPlayerContextView, Hook.Setter>,        UPDATE<IPlayerContextView>,        ON_SET,        FSM_STATE_ENTER<IPlayerContextView>    {        PlayerConfig cfg => facade.Config; PlayerBlackboard bb => facade.API_Blackboard<PlayerBlackboard>(); PlayerContextData mutateCtx => facade.API_Context<PlayerContextData>();        internal class Setter : DataSetter<bool>        {            [ShowInInspector] public bool PressedHook            {                get => Get;                set => ExplicitSet(value);            }        }        public Hook(IPublisher publisher, PlayerController facade) : base(publisher, facade) { }        public void MutateUsingNewSetValues()        {            if (!SetContext.PressedHook) return;                        if (mutateCtx.isHooking)            {                if (bb.hook.ResetHook()) Unhooked();                else SetContext.PressedHook = true;            }            else            {                mutateCtx.isHooking = true;                bb.hook.CastHook(mutateCtx.mousePos, cfg.hook.hookForce);            }        }        void Unhooked()        {            mutateCtx.isHooking = false;            mutateCtx.isFinishing = false;            mutateCtx.targetIsFinishInputAvaliable = null;            mutateCtx.targetStunPublisher = null;            mutateCtx.isHookLatchedOntoTarget = false;            mutateCtx.targetIsHookedBySomething.Publish((false, facade.Actions.Finisher));                    Debug.Log("Player unhooked from target");        }                public override void Execute(IPlayerContextView ctx)        {            bb.hookAimPos.transform.position = ctx.mousePos;        }        public void OnEnterState(IPlayerContextView ctx)        {                    }    }        class Attack : BoundSetFunctionality<PlayerController, IPlayerContextView, Attack.Setter>,        ON_SET,        FSM_STATE_ENTER<IPlayerContextView>    {        PlayerConfig cfg => facade.Config; PlayerBlackboard bb => facade.API_Blackboard<PlayerBlackboard>(); PlayerContextData mutateCtx => facade.API_Context<PlayerContextData>();        internal class Setter : DataSetter<bool>        {            [ShowInInspector] public bool PressedAttack => Get;        }        public Attack(IPublisher publisher, PlayerController facade) : base(publisher, facade) { }        protected override void Awake()        {            AttackEndDelegate = AttackEnd;            DeactiveAtkColliders();        }        Action AttackEndDelegate;        public void MutateUsingNewSetValues()        {            if (mutateCtx.isHooking && bb.hook.phase == global::Hook.HookPhases.HookedToSomething)            {                facade.Actions.HookAttack.Publish(mutateCtx);                facade.Input.Hook.Publish(false);                return;            }            if (!SetContext.PressedAttack) return;            if (mutateCtx.isAttacking) return;            mutateCtx.isAttacking = true;            var animenum = mutateCtx.attackDir switch            {                PlayerBlackboard.AttackDir.Right => PlayerConfig.PlayerAnimations.AttackFront,                PlayerBlackboard.AttackDir.Left => PlayerConfig.PlayerAnimations.AttackFront,                PlayerBlackboard.AttackDir.Up => PlayerConfig.PlayerAnimations.AttackUp,                PlayerBlackboard.AttackDir.Down => PlayerConfig.PlayerAnimations.AttackDown,                _ => PlayerConfig.PlayerAnimations.AttackFront            };            DeactiveAtkColliders();            var currentAttackDirPair = bb.attackColliders.GetInArray(mutateCtx.attackDir);            currentAttackDirPair.obj.gameObject.SetActive(true);            cfg.animHandle.PlayThenOnEnd(bb.animator, animenum, AttackEndDelegate);        }        void AttackEnd()        {            mutateCtx.isAttacking = false;            DeactiveAtkColliders();        }                void DeactiveAtkColliders()        {            foreach (var pair in bb.attackColliders)                pair.obj.gameObject.SetActive(false);        }                public void OnEnterState(IPlayerContextView ctx)        {            Debug.Log("Entered Attack State");        }    }            class CardinalAttackDirection : BoundSetFunctionality<PlayerController, IPlayerContextView, CardinalAttackDirection.Setter>,        UPDATE<IPlayerContextView>    {        PlayerConfig cfg => facade.Config; PlayerBlackboard bb => facade.API_Blackboard<PlayerBlackboard>(); PlayerContextData mutateCtx => facade.API_Context<PlayerContextData>();        internal class Setter : DataSetter<Vector2>         {            [ShowInInspector] public Vector2 mousePos => Get;        }        public CardinalAttackDirection(IPublisher publisher, PlayerController facade) : base(publisher, facade) { }        public override void Execute(IPlayerContextView ctx)        {             mutateCtx.attackDir = bb.attackBounds.GetBound(SetContext.mousePos);            bb.attackDirIndicator.rotation = mutateCtx.attackDir switch            {                PlayerBlackboard.AttackDir.Up => Quaternion.Euler(0, 0, 0),                PlayerBlackboard.AttackDir.Down => Quaternion.Euler(0, 0, 180),                PlayerBlackboard.AttackDir.Left => Quaternion.Euler(0, 0, 90),                PlayerBlackboard.AttackDir.Right => Quaternion.Euler(0, 0, -90),                _ => bb.attackDirIndicator.rotation            };        }    }        class Look : BoundSetFunctionality<PlayerController, IPlayerContextView, Look.Setter>,        UPDATE<IPlayerContextView>    {        PlayerConfig cfg => facade.Config; PlayerBlackboard bb => facade.API_Blackboard<PlayerBlackboard>(); PlayerContextData mutateCtx => facade.API_Context<PlayerContextData>();        internal class Setter : DataSetter<Vector2>        {            [ShowInInspector] public Vector2 mousePos => Get;        }        public Look(IPublisher publisher, PlayerController facade) : base(publisher, facade) { }        public override void Execute(IPlayerContextView ctx)        {            mutateCtx.mousePos = Camera.main.ScreenToWorldPoint(SetContext.mousePos);            var dir = CheckIfAnyContains(cfg.facing.callbackZones, SetContext.mousePos);            if (dir == PlayerConfig.MouseZones.LeftScreen)            {                bb.facingBody.rotation = Quaternion.Euler(0, 0, 0);                mutateCtx.facingDirection = IEntityCtx.FaceDirection.Left;            }            else if (dir == PlayerConfig.MouseZones.RightScreen)            {                bb.facingBody.rotation = Quaternion.Euler(0, 180, 0);                mutateCtx.facingDirection = IEntityCtx.FaceDirection.Right;            }        }    }    class InAir : UnboundFunctionality<PlayerController, IPlayerContextView>,        FIXED_UPDATE<IPlayerContextView>,        FSM_STATE_ENTER<IPlayerContextView>    {        PlayerConfig cfg => facade.Config; PlayerBlackboard bb => facade.API_Blackboard<PlayerBlackboard>(); PlayerContextData mutateCtx => facade.API_Context<PlayerContextData>();        public InAir(PlayerController facade) : base(facade) { }                protected override void Awake()            => mutateCtx.fallingWithoutJumpingFirst = new DelayBuffer<bool>(false, cfg.fall.fallingBufferWindow);                public override void Execute(IPlayerContextView ctx)        {            mutateCtx.isGrounded.Value = IsGrounded();            if(!ctx.IsGrounded) bb.rb.AddForce(-facade.transform.up * cfg.fall.scalar, cfg.fall.forceMode);            mutateCtx.fallingWithoutJumpingFirst.SetBuffered(!ctx.IsGrounded && !ctx.isJumping && ctx.canJumpCoyote);        }                bool IsGrounded()        {            for (int i = 0; i < bb.feetPoints.Length; i++)                if (Physics2D.Raycast(bb.feetPoints[i].position, -facade.transform.up, cfg.fall.checkDist, cfg.fall.mask)) return true;            return false;        }        public void OnEnterState(IPlayerContextView ctx)        {            Debug.Log("Entetered State: InAir");        }    }    class Friction : UnboundFunctionality<PlayerController, IPlayerContextView>,        FIXED_UPDATE<IPlayerContextView>    {        PlayerConfig cfg => facade.Config; PlayerBlackboard bb => facade.API_Blackboard<PlayerBlackboard>(); PlayerContextData mutateCtx => facade.API_Context<PlayerContextData>();        public Friction(PlayerController facade) : base(facade) { }        public override PipelineBuilder<IPlayerContextView> InjectSteps(PipelineBuilder<IPlayerContextView> builder)            => builder.Add_ShortCircuit(new FuncCtxPredicate<IPlayerContextView>(_ => !mutateCtx.isGrounded));        public override void Execute(IPlayerContextView ctx)        {            float amount = Mathf.Min(Mathf.Abs(bb.rb.linearVelocityX), cfg.friction.frictionScalar);            amount *= Mathf.Sign(bb.rb.linearVelocityX);            bb.rb.AddForce(Vector2.right * -amount, ForceMode2D.Impulse);        }    }    class Jump : BoundSetFunctionality<PlayerController, IPlayerContextView, Jump.Setter>,        FIXED_UPDATE<IPlayerContextView>,        ON_SET,        FSM_STATE_ENTER<IPlayerContextView>    {        PlayerConfig cfg => facade.Config; PlayerBlackboard bb => facade.API_Blackboard<PlayerBlackboard>(); PlayerContextData mutateCtx => facade.API_Context<PlayerContextData>();        public class Setter : DataSetter<bool>        {            [ShowInInspector] public bool isActive => Get;        }        public Jump(IPublisher publisher, PlayerController facade) : base(publisher, facade) { }        public override PipelineBuilder<IPlayerContextView> InjectSteps(PipelineBuilder<IPlayerContextView> builder)            => builder.Add_ShortCircuit(new FuncCtxPredicate<IPlayerContextView>(ctx => !SetContext.isActive));        protected override void Awake()        {            facade.API_Context<PlayerContextData>().isGrounded.Reactions.Add(Grounded);            UseExecutionBuffer(() => mutateCtx.canJumpCoyote && !mutateCtx.FallingWithoutJumpingFirst, cfg.jump.coyoteInputWindow);            SetContext.OnSetEvent.Add(ResetExeConsumeBuffer);        }        public override void Execute(IPlayerContextView ctx)        {            ctx.JumpCurve.Value += cfg.jump.jumpCurveRate;            var mult = ctx.JumpCurve.Evaluate;            bb.rb.AddForce(new Vector2(0, cfg.jump.scalar) * mult, cfg.jump.forceMode);            facade.API_Context<PlayerContextData>().isJumping = true;        }        public void MutateUsingNewSetValues()           {            bool pressedJump = SetContext.isActive;            bool falling = bb.rb.linearVelocityY < 0f;            bool canJump = !mutateCtx.FallingWithoutJumpingFirst && !mutateCtx.isJumping && mutateCtx.canJumpCoyote && !mutateCtx.landing;                        if (pressedJump && canJump)            {                bb.jumpCurve.DynamicStart(Operation.Increase);                if(falling) bb.rb.linearVelocityY = 0;            }            else {                 if(mutateCtx.isJumping) facade.API_Context<PlayerContextData>().canJumpCoyote = false;                facade.API_Context<PlayerContextData>().isJumping = false;                bb.jumpCurve.DynamicStart(Operation.Decrease);                bb.jumpCurve.Value = 0;            }                    }        void Grounded(bool v)        {            bool attacking = facade.API_Context<PlayerContextData>().isAttacking;            if (v) {                bb.jumpCurve.Value = 0;                 facade.API_Context<PlayerContextData>().isJumping = false;                facade.API_Context<PlayerContextData>().canJumpCoyote = true;                facade.API_Context<PlayerContextData>().fallingWithoutJumpingFirst.SetNotBuffered(false);                 if(!attacking) facade.StartCoroutine(C_Landing());            }        }        IEnumerator C_Landing()        {            mutateCtx.landing = true;            cfg.animHandle.Play(bb.animator, PlayerConfig.PlayerAnimations.Land);            yield return new WaitForSeconds(cfg.jump.landTime);            mutateCtx.landing = false;        }        public void OnEnterState(IPlayerContextView ctx)        {            Debug.Log("Entered Jump State");            cfg.animHandle.Play(bb.animator, PlayerConfig.PlayerAnimations.JumpStart);        }            }        class Move : BoundSetFunctionality<PlayerController, IPlayerContextView, Move.Setter>,        FIXED_UPDATE<IPlayerContextView>,        FSM_STATE_ENTER<IPlayerContextView>    {        PlayerConfig cfg => facade.Config; PlayerBlackboard bb => facade.API_Blackboard<PlayerBlackboard>(); PlayerContextData mutateCtx => facade.API_Context<PlayerContextData>();        internal class Setter : DataSetter<(bool, float)>        {            [ShowInInspector] public bool isActive => Get.Item1;            [ShowInInspector] public float moveX => isActive ? base.Get.Item2 : NumEX.ZeroF;        }                public Move(IPublisher publisher, PlayerController facade) : base(publisher, facade) { }        public override PipelineBuilder<IPlayerContextView> InjectSteps(PipelineBuilder<IPlayerContextView> builder)            => builder.Add_ShortCircuit(                    new FuncCtxPredicate<IPlayerContextView>(_ => !SetContext.isActive),                    shortCircuited: new IResolvable[] { new Callback(AnimateStopMove) })                .Add_Middleware(AnimateMove);        public override void Execute(IPlayerContextView ctx)        {            var targSpeed = SetContext.moveX * cfg.move.speedScalar;            var speedDiff = targSpeed - bb.rb.linearVelocity.x;            var accel = Mathf.Abs(targSpeed) > 0.01f ? cfg.move.acceleration : cfg.move.deceleration;            var movement = Mathf.Pow(Mathf.Abs(speedDiff), 2) * accel * Mathf.Sign(speedDiff);            bb.rb.AddForce(movement * Vector2.right, cfg.move.forceMode2d);            mutateCtx.isMoving = SetContext.moveX != 0;        }        void AnimateMove(IPlayerContextView ctx)        {            if (facade.FSM.CurrentStateType == typeof(Move))                cfg.animHandle.Play(bb.animator, PlayerConfig.PlayerAnimations.Move);        }        void AnimateStopMove()        {            if (facade.FSM.CurrentStateType == typeof(Move))                cfg.animHandle.Play(bb.animator, PlayerConfig.PlayerAnimations.Idle);        }        public void OnEnterState(IPlayerContextView ctx)        {            Debug.Log("Entered Move State");        }    }}